mapper.select:
select
from t_course_scheduling cs left join t_classroom classroom on cs.classroom_id = classroom.id left join t_course course on cs.course_id = course.id left join t_teacher teacher on cs.teacher_id = teacher.id where 1=1
and ${ew.sqlSegment}

select distinct concat(date_format(cs.attend_time, '%H:%i'), '-', date_format(cs.finish_time, '%H:%i')) time
from t_course_scheduling cs

    inner join t_course_scheduling_class csc on cs.id = csc.course_scheduling_id

where date in

    #{item}


    and cs.classroom_id = #{classroomId}


    and cs.teacher_id = #{teacherId}


    and csc.class_id = #{classId}

order by time

select date, concat(date_format(cs.attend_time, '%H:%i'), '-', date_format(cs.finish_time, '%H:%i')) time, classroom.name classroomName, course.name courseName, course.background_color backgroundColor, teacher.name teacherName from t_course_scheduling cs
inner join t_course_scheduling_class csc on cs.id = csc.course_scheduling_id
left join t_classroom classroom on cs.classroom_id = classroom.id left join t_course course on cs.course_id = course.id left join t_teacher teacher on cs.teacher_id = teacher.id where date between #{startDate} and #{endDate}
and cs.classroom_id = #{classroomId}
and cs.teacher_id = #{teacherId}
and csc.class_id = #{classId}
order by date, time

select teacher.id, teacher.name, count(cs.id) count
from t_teacher teacher
left join t_course_scheduling cs on teacher.id = cs.teacher_id
    and cs.date between #{startDate} and #{endDate}
group by teacher.id, teacher.name
order by count desc;

select course.id, course.name, course.background_color color, count(cs.id) count
from t_course course
left join t_course_scheduling cs on course.id = cs.course_id
    and cs.date between #{startDate} and #{endDate}
group by course.id, course.name
order by count desc;

select

from t_course_scheduling cs
inner join t_course_scheduling_class csc on cs.id = csc.course_scheduling_id
left join t_classroom classroom on cs.classroom_id = classroom.id
left join t_course course on cs.course_id = course.id
left join t_teacher teacher on cs.teacher_id = teacher.id
where csc.class_id = #{classId}

    and cs.date >= #{startDate}


    and cs.date <= #{endDate}

order by cs.date, cs.attend_time
